class Solution:
    def numTilePossibilities(self, tiles):
        """
        :type tiles: str
        :rtype: int
        """
        from collections import Counter

        count = Counter(tiles)

        def backtrack():
            total = 0
            for tile in count:
                if count[tile] > 0:
                    total += 1  # Count this sequence
                    count[tile] -= 1
                    total += backtrack()  # Continue building
                    count[tile] += 1
            return total

        return backtrack()
